import React, { Component, useEffect } from "react";
import "./App.css";
class Slider extends Component {
  constructor(props) {
    super(props);
    this.state = {
      number: 0,
      listOfImages: [
        {
          id: 1,
          src: "https://images.unsplash.com/photo-1587620962725-abab7fe55159?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=1631&q=80",
        },

        {
          id: 2,
          src: "https://images.unsplash.com/photo-1633356122544-f134324a6cee?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=1470&q=80",
        },
        {
          id: 3,
          src: "https://cdn.pixabay.com/photo/2015/12/04/14/05/code-1076536_960_720.jpg",
        },
      ],
    };
  }

  cycle = () => {
    if (this.state.number != this.state.listOfImages.length - 1) {
      this.setState({ number: this.state.number + 1 });
    } else {
      this.setState({ number: 0 });
    }
    console.log(this.state.number);
  };

  firstCycle = () => setTimeout(this.cycle, 8000);

  /*componentDidMount() {
    setTimeout(() => {
      if (this.state.number === 0) {
        this.setState({ number: 1 });
      } else {
        this.setState({ number: 0 });
      }
    }, 5000);
  }*/
  render() {
    this.firstCycle();
    //setInterval(this.cycle, 5000);
    return (
      <div className="divSlider">
        <img
          className="photo1"
          src={this.state.listOfImages[this.state.number].src}
          alt="programmingPhoto1"
          onChange={() => setTimeout(this.cycle, 5000)}
        />
      </div>
    );
  }
}
